Method.Source:
public void initValue()
{
    super();
    this.CompanyId = curext();
}

public boolean isValidForCompany(CompanyId   _companyId)
{
    #define.datCompany('DAT')

    if (this.RecId && _companyId)
    {
        if (this.CompanyId == _companyId || ! this.CompanyId || !strCmp(strUpr(_companyId), #datCompany))
        {
            return true;
        }
    }

    return false;
}

public static FWFTextBlockTable find(
    RefRecId    _recId,
    boolean     _update = false)
{
    FWFTextBlockTable  textBlockTable;

    textBlockTable.selectForUpdate(_update);

    if (_recId)
    {
        select firstonly textBlockTable
            where textBlockTable.RecId == _recId;
    }

    return textBlockTable;
}

public static FWFTextBlockTable findNameModule(
    FWFTextBlockName    _name,
    FWFTextBlockModule  _module,
    DataAreaId          _dataAreaId = curext(),
    boolean             _update     = false
    )
{
    FWFTextBlockTable   textBlockTable;

    textBlockTable.selectForUpdate(_update);

    if (_name)
    {
        select firstonly textBlockTable
            where  textBlockTable.Name      == _name
               &&  textBlockTable.Module    == _module
               && (textBlockTable.CompanyId == _dataAreaId || !textBlockTable.CompanyId);
    }

    return textBlockTable;
}

public static void lookup(FormControl _control, FWFTextBlockModule _module)
{
    SysTableLookup sysTableLookup;

    sysTableLookup  = SysTableLookup::newParameters(tableNum(FWFTextBlockTable), _control);

    sysTableLookup.addLookupfield(fieldNum(FWFTextBlockTable, Name));
    sysTableLookup.addLookupfield(fieldNum(FWFTextBlockTable, CompanyId));
    sysTableLookup.parmQuery(FWFTextBlockTable::lookupQuery(_module));

    sysTableLookup.performFormLookup();
}

public static query lookupQuery(FWFTextBlockModule	_module)
{
    Query                   query = new Query();
    QueryBuildDataSource    qbds;
    str                     qVal;

    qbds = query.addDataSource(tableNum(FWFTextBlockTable));

    if (_module)
    {
        qbds.addRange(fieldNum(FWFTextBlockTable, Module)).value(queryValue(_module));
    }

    qVal = strFmt('((%1.%2 == "%3") || (%1.%2 == "%4"))',
                    query.dataSourceTable(tableNum(FWFTextBlockTable)).name(),
                    fieldStr(FWFTextBlockTable, CompanyId),
                    queryValue(curext()),
                    SysQuery::valueUnlimited());
    qbds.addRange(fieldNum(FWFTextBlockTable, CompanyId)).value(qVal);

    return query;
}

public static Common lookupReference(FormReferenceControl _control, FWFTextBlockModule _module)
{
    SysReferenceTableLookup sysTableLookup;

    sysTableLookup  = SysReferenceTableLookup::newParameters(tableNum(FWFTextBlockTable), _control);

    sysTableLookup.addLookupfield(fieldNum(FWFTextBlockTable, Name));
    sysTableLookup.addLookupfield(fieldNum(FWFTextBlockTable, CompanyId));
    sysTableLookup.parmQuery(FWFTextBlockTable::lookupQuery(_module));

    return sysTableLookup.performFormLookup();
}

public static void initSetupRefRecId()
{
    FWFTextblockTable       table;
    FWFTextblockTableParm   parm;

    ttsbegin;

    while select forupdate table
    notexists join parm
        where parm.RecId == table.SetupRefRecId
    {
        parm.initValue();
        parm.insert();

        if (parm.RecId)
        {
            table.SetupRefRecId = parm.RecId;
            table.doUpdate();
        }
    }

    ttscommit;
}
